UPDATE customer_case
client_name = #{clientName}, industry = #{industry}, description = #{description}, highlight = #{highlight}, image_url = #{imageUrl}, image_keyword = #{imageKeyword}, products = #{products}, quantity = #{quantity}, sort_order = #{sortOrder}, is_visible = #{isVisible}, update_time = #{updateTime}
